import React from 'react';
import { Helmet } from 'react-helmet-async';

import type { SEOHeadProps } from './SEOHead.types';
import { validateSEOProps } from './utils';

export const SEOHead: React.FC<SEOHeadProps> = ({
	title,
	description,
	canonicalUrl,
	lang = 'ru',
	robots = 'index, follow',
	ogTitle,
	ogDescription,
	ogType = 'website',
	ogUrl,
	ogImage,
	twitterCard = 'summary_large_image',
	favicon = '/favicon.ico',
	appleTouchIcon,
	charset = 'UTF-8',
	viewport = 'width=device-width, initial-scale=1.0',
	children,
	dataTestId = 'SEOHead',
}) => {
	if (process.env.NODE_ENV !== 'production') {
		validateSEOProps({ title, description });
	}

	const robotsContent = Array.isArray(robots) ? robots.join(', ') : robots;
	const finalOgTitle = ogTitle || title;
	const finalOgDescription = ogDescription || description;
	const finalOgUrl = ogUrl || canonicalUrl;

	return (
		<Helmet data-testid={dataTestId}>
			<html lang={lang} />
			<meta charSet={charset} />
			<meta name="viewport" content={viewport} />
			<title>{title}</title>
			<meta name="description" content={description} />
			<meta name="robots" content={robotsContent} />
			<link rel="canonical" href={canonicalUrl} />
			<meta property="og:title" content={finalOgTitle} />
			<meta property="og:description" content={finalOgDescription} />
			<meta property="og:type" content={ogType} />
			<meta property="og:url" content={finalOgUrl} />
			{ogImage && <meta property="og:image" content={ogImage} />}
			<meta name="twitter:card" content={twitterCard} />
			<link rel="icon" href={favicon} />
			{appleTouchIcon && <link rel="apple-touch-icon" href={appleTouchIcon} />}
			{children}
		</Helmet>
	);
};

SEOHead.displayName = 'SEOHead';
